func solve(s: String): Int64 {
    let n = s.length();

    for i from 0 to n - 1 {
        let j = n - 1 - i;

        // In languages supporting string indexing like this, 
        // we compare characters at index i and index j.
        // Since we iterate i upwards, the first match found is the smallest i.
        if s[i] == s[j] {
            return i as Int64;
        }
    }

    return -1 as Int64;
}

